import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';

function LogoIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
      <circle cx="12" cy="12" r="9.5" stroke="currentColor" strokeWidth="1.4" />
      <path
        d="M12 8.5v3.8l2.5 2.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <circle cx="12" cy="12" r="1.2" fill="currentColor" />
    </svg>
  );
}

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 24);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <motion.nav
      className={`navbar${scrolled ? ' scrolled' : ''}`}
      initial={{ opacity: 0, y: -16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, ease: 'easeOut' }}
    >
      <div className="container navbar-inner">
        <a href="/" className="logo">
          <span className="logo-icon">
            <LogoIcon />
          </span>
          <span>
            <span style={{ fontWeight: 500 }}>Safe</span>
            <span style={{ fontWeight: 700 }}>Load</span>
          </span>
          <span className="logo-tag">AI</span>
        </a>

        <nav className="nav-links">
          <a href="/" className="nav-link">Home</a>
          <a href="/about" className="nav-link active">About Us</a>
          <a href="/solution" className="nav-link">Our Solution</a>
          <motion.a
            href="/join"
            className="btn-primary"
            whileHover={{ scale: 1.03 }}
            whileTap={{ scale: 0.97 }}
          >
            Join Pilot Program
          </motion.a>
        </nav>
      </div>
    </motion.nav>
  );
}
